namespace sv_e7473c7624644257b82ee2ce4b0e6ec4.Models;

public class WizardState
{
    // Step 1: Personal Info
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";

    // Step 2: Experience
    public List<JobEntry> JobHistory { get; set; } = [];

    // Step 3: References
    public List<Reference> References { get; set; } = [];

    // Progress tracking
    public HashSet<int> CompletedSteps { get; set; } = [];
    public int CurrentStep { get; set; } = 1;

    public const int TotalSteps = 4;
}

public class JobEntry
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Years { get; set; } = "";
}

public class Reference
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string ContactInfo { get; set; } = "";
}

using System.Collections.Concurrent;
using sv_e7473c7624644257b82ee2ce4b0e6ec4.Models;

namespace sv_e7473c7624644257b82ee2ce4b0e6ec4.Services;

/// <summary>
/// Singleton store keyed by session ID (from cookie).
/// Both static SSR layout and interactive pages resolve the same instance.
/// </summary>
public class WizardStateStore
{
    private readonly ConcurrentDictionary<string, WizardState> _states = new();

    public WizardState GetOrCreate(string sessionId)
        => _states.GetOrAdd(sessionId, _ => new WizardState());

    public void Remove(string sessionId)
        => _states.TryRemove(sessionId, out _);
}

namespace sv_e7473c7624644257b82ee2ce4b0e6ec4.Services;

/// <summary>
/// Ensures every request has a "WizardSessionId" cookie so both the
/// static layout and interactive pages can share state via the store.
/// </summary>
public class WizardSessionMiddleware
{
    private readonly RequestDelegate _next;
    public const string CookieName = "WizardSessionId";

    public WizardSessionMiddleware(RequestDelegate next) => _next = next;

    public async Task InvokeAsync(HttpContext context)
    {
        if (!context.Request.Cookies.ContainsKey(CookieName))
        {
            var sessionId = Guid.NewGuid().ToString("N");
            context.Response.Cookies.Append(CookieName, sessionId, new CookieOptions
            {
                HttpOnly = true,
                SameSite = SameSiteMode.Strict,
                IsEssential = true,
                MaxAge = TimeSpan.FromHours(4)
            });
            // Also make it available to downstream components on this first request
            context.Items[CookieName] = sessionId;
        }

        await _next(context);
    }
}

