@* Static component — no render mode needed. Rendered inside the SSR layout. *@

<nav aria-label="Wizard progress" class="wizard-progress d-flex align-items-center gap-2 me-auto">
    @for (int i = 1; i <= TotalSteps; i++)
    {
        var step = i;
        var label = step switch
        {
            1 => "Personal Info",
            2 => "Experience",
            3 => "References",
            4 => "Review",
            _ => $"Step {step}"
        };

        var isCompleted = CompletedSteps.Contains(step);
        var isCurrent = step == CurrentStep;

        <div class="d-flex align-items-center">
            <span class="badge rounded-pill @(isCompleted ? "bg-success" : isCurrent ? "bg-primary" : "bg-secondary")">
                @(isCompleted ? "✓" : step)
            </span>
            <span class="ms-1 small @(isCurrent ? "fw-bold" : "")">@label</span>

            @if (step < TotalSteps)
            {
                <span class="mx-2 text-muted">—</span>
            }
        </div>
    }
    <span class="ms-2 small text-muted">Step @CurrentStep of @TotalSteps</span>
</nav>

@code {
    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public HashSet<int> CompletedSteps { get; set; } = [];
    [Parameter] public int TotalSteps { get; set; }
}

@* Base component that handles the SSR→Interactive session ID handoff.
   Each wizard page inherits from this. *@

@using Microsoft.AspNetCore.Components
@using sv_e7473c7624644257b82ee2ce4b0e6ec4.Services
@using sv_e7473c7624644257b82ee2ce4b0e6ec4.Models

@inject WizardStateStore StateStore
@inject PersistentComponentState PersistentState
@inject IHttpContextAccessor HttpContextAccessor

@code {
    protected WizardState Wizard { get; private set; } = new();
    protected string SessionId { get; private set; } = "";
    private PersistingComponentStateSubscription _subscription;

    protected override void OnInitialized()
    {
        // During prerender (SSR): HttpContext is available → read the cookie.
        // During interactive mode: HttpContext is null → restore from PersistentComponentState.
        if (PersistentState.TryTakeFromJson<string>("WizardSessionId", out var restored) && restored is not null)
        {
            SessionId = restored;
        }
        else
        {
            SessionId = WizardSessionHelper.GetSessionId(HttpContextAccessor.HttpContext) ?? "";
            _subscription = PersistentState.RegisterOnPersisting(() =>
            {
                PersistentState.PersistAsJson("WizardSessionId", SessionId);
                return Task.CompletedTask;
            });
        }

        if (!string.IsNullOrEmpty(SessionId))
        {
            Wizard = StateStore.GetOrCreate(SessionId);
        }
    }

    /// <summary>Call after the user saves data to update the store's step tracking.</summary>
    protected void MarkStepCompleted(int step)
    {
        Wizard.CompletedSteps.Add(step);
    }

    public void Dispose()
    {
        _subscription.Dispose();
    }
}

