@page "/apply/personal-info"
@rendermode InteractiveServer
@inherits WizardStepBase
@implements IDisposable
@using sv_e7473c7624644257b82ee2ce4b0e6ec4.Models
@inject NavigationManager Nav

<PageTitle>Step 1: Personal Info</PageTitle>

<h3>Personal Information</h3>

<EditForm Model="Wizard" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="Wizard.FullName" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="Wizard.Email" />
    </div>
    <div class="mb-3">
        <label class="form-label">Phone</label>
        <InputText class="form-control" @bind-Value="Wizard.Phone" />
    </div>
    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    protected override void OnInitialized()
    {
        base.OnInitialized();
        Wizard.CurrentStep = 1;
    }

    private void Next()
    {
        MarkStepCompleted(1);
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@inherits WizardStepBase
@implements IDisposable
@using sv_e7473c7624644257b82ee2ce4b0e6ec4.Models
@inject NavigationManager Nav

<PageTitle>Step 2: Experience</PageTitle>

<h3>Work Experience</h3>

@for (int i = 0; i < Wizard.JobHistory.Count; i++)
{
    var index = i;
    <div class="card mb-3 p-3">
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="Wizard.JobHistory[index].Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Title</label>
            <input class="form-control" @bind="Wizard.JobHistory[index].Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="Wizard.JobHistory[index].Years" />
        </div>
        <button class="btn btn-sm btn-outline-danger" @onclick="() => RemoveJob(index)">Remove</button>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddJob">+ Add Job</button>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    protected override void OnInitialized()
    {
        base.OnInitialized();
        Wizard.CurrentStep = 2;
    }

    private void AddJob() => Wizard.JobHistory.Add(new JobEntry());
    private void RemoveJob(int index) => Wizard.JobHistory.RemoveAt(index);
    private void Back() => Nav.NavigateTo("/apply/personal-info");

    private void Next()
    {
        MarkStepCompleted(2);
        Nav.NavigateTo("/apply/references");
    }
}

