@page "/apply/review"
@rendermode InteractiveServer
@inherits WizardStepBase
@implements IDisposable
@using sv_e7473c7624644257b82ee2ce4b0e6ec4.Models
@inject NavigationManager Nav

<PageTitle>Step 4: Review</PageTitle>

<h3>Review Your Application</h3>

<div class="card mb-3 p-3">
    <h5>Personal Info</h5>
    <p><strong>Name:</strong> @Wizard.FullName</p>
    <p><strong>Email:</strong> @Wizard.Email</p>
    <p><strong>Phone:</strong> @Wizard.Phone</p>
</div>

<div class="card mb-3 p-3">
    <h5>Experience</h5>
    @if (Wizard.JobHistory.Count == 0)
    {
        <p class="text-muted">No entries</p>
    }
    @foreach (var job in Wizard.JobHistory)
    {
        <p>@job.Title at @job.Company (@job.Years)</p>
    }
</div>

<div class="card mb-3 p-3">
    <h5>References</h5>
    @if (Wizard.References.Count == 0)
    {
        <p class="text-muted">No entries</p>
    }
    @foreach (var r in Wizard.References)
    {
        <p>@r.Name — @r.Relationship (@r.ContactInfo)</p>
    }
</div>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@if (_submitted)
{
    <div class="alert alert-success mt-3">Application submitted successfully!</div>
}

@code {
    private bool _submitted;

    protected override void OnInitialized()
    {
        base.OnInitialized();
        Wizard.CurrentStep = 4;
    }

    private void Back() => Nav.NavigateTo("/apply/references");

    private void Submit()
    {
        MarkStepCompleted(4);
        _submitted = true;
        // In production: save to DB, send email, etc.
    }
}

