@page "/apply/experience"
@rendermode InteractiveServer
@inherits WizardStepBase
@implements IDisposable
@using sv_e7473c7624644257b82ee2ce4b0e6ec4.Models
@inject NavigationManager Nav

<PageTitle>Step 2: Experience</PageTitle>

<h3>Work Experience</h3>

@for (int i = 0; i < Wizard.JobHistory.Count; i++)
{
    var index = i;
    <div class="card mb-3 p-3">
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="Wizard.JobHistory[index].Company" />
        </div>
        <div class="mb-2">
